ORDER BY u.discnt_usage_id ASC ORDER BY u.discnt_usage_id DESC ORDER BY u.discnt_nm ASC ORDER BY u.discnt_nm DESC ORDER BY u.reg_date ASC ORDER BY u.reg_date DESC ORDER BY u.reg_date DESC
