UPDATE pm_discnt_usage /* base.ec.pm :: PmDiscntUsage :: updateSelective */
site_id = #{siteId}, discnt_id = #{discntId}, discnt_nm = #{discntNm}, member_id = #{memberId}, order_id = #{orderId}, order_item_id = #{orderItemId}, prod_id = #{prodId}, discnt_type_cd = #{discntTypeCd}, discnt_value = #{discntValue}, discnt_amt = #{discntAmt}, used_date = #{usedDate},
WHERE discnt_usage_id = #{discntUsageId}
